# CoAP Constants
COAP_VERSION = 1
COAP_PORT = 5683

# CoAP Message Types
CON = 0  # Confirmable
NON = 1  # Non-confirmable
ACK = 2  # Acknowledgement
RST = 3  # Reset

# CoAP Method Codes
EMPTY = 0
GET = 1
POST = 2
PUT = 3
DELETE = 4

# CoAP Response Codes
CONTENT = (2, 5)       # 2.05 Content
CHANGED = (2, 4)       # 2.04 Changed
BAD_REQUEST = (4, 0)   # 4.00 Bad Request
NOT_FOUND = (4, 4)     # 4.04 Not Found
METHOD_NOT_ALLOWED = (4, 5)  # 4.05 Method Not Allowed

# Content Format
TEXT_PLAIN = 0
APP_JSON = 50


class CoapMessage:
    """Lightweight CoAP message parser and builder."""

    def __init__(self):
        self.version = COAP_VERSION
        self.msg_type = ACK
        self.code_class = 0
        self.code_detail = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''

    @staticmethod
    def parse(data):
        """Parse raw bytes into a CoapMessage."""
        msg = CoapMessage()
        if len(data) < 4:
            return None

        first_byte = data[0]
        msg.version = (first_byte >> 6) & 0x03
        msg.msg_type = (first_byte >> 4) & 0x03
        token_length = first_byte & 0x0F

        second_byte = data[1]
        msg.code_class = (second_byte >> 5) & 0x07
        msg.code_detail = second_byte & 0x1F

        msg.message_id = struct.unpack('!H', data[2:4])[0]

        offset = 4
        if token_length > 0:
            msg.token = data[offset:offset + token_length]
            offset += token_length

        # Parse options
        option_number = 0
        while offset < len(data):
            if data[offset] == 0xFF:
                offset += 1
                msg.payload = data[offset:]
                break

            option_delta = (data[offset] >> 4) & 0x0F
            option_length = data[offset] & 0x0F
            offset += 1

            if option_delta == 13:
                option_delta = data[offset] + 13
                offset += 1
            elif option_delta == 14:
                option_delta = struct.unpack('!H', data[offset:offset + 2])[0] + 269
                offset += 2

            if option_length == 13:
                option_length = data[offset] + 13
                offset += 1
            elif option_length == 14:
                option_length = struct.unpack('!H', data[offset:offset + 2])[0] + 269
                offset += 2

            option_number += option_delta
            option_value = data[offset:offset + option_length]
            offset += option_length

            msg.options.append((option_number, option_value))

        return msg

    def get_uri_path(self):
        """Extract URI path from options (option number 11)."""
        parts = []
        for opt_num, opt_val in self.options:
            if opt_num == 11:  # Uri-Path
                parts.append(opt_val.decode('utf-8'))
        return '/' + '/'.join(parts) if parts else '/'

    def get_method(self):
        """Get the CoAP method code."""
        if self.code_class == 0:
            return self.code_detail
        return 0

    def build_response(self, msg_type, code, token, message_id, payload=b'', content_format=None):
        """Build a CoAP response message as bytes."""
        token_length = len(token)
        first_byte = (COAP_VERSION << 6) | (msg_type << 4) | token_length
        second_byte = (code[0] << 5) | code[1]

        result = struct.pack('!BBH', first_byte, second_byte, message_id)

        if token_length > 0:
            result += token

        # Add Content-Format option (option 12) if specified
        if content_format is not None:
            option_delta = 12
            if content_format < 256:
                option_length = 1
                result += bytes([((option_delta & 0x0F) << 4) | (option_length & 0x0F)])
                result += bytes([content_format])
            else:
                option_length = 2
                result += bytes([((option_delta & 0x0F) << 4) | (option_length & 0x0F)])
                result += struct.pack('!H', content_format)

        if payload:
            result += b'\xFF'
            if isinstance(payload, str):
                result += payload.encode('utf-8')
            else:
                result += payload

        return result


class DeviceState:
    """Manages device sensor readings and actuator states."""

    def __init__(self):
        self.light_state = False
        self.light_brightness = 0
        self._temp_sensor = None
        self._light_pin = None
        self._pwm_light = None
        self._init_hardware()

    def _init_hardware(self):
        """Initialize hardware peripherals."""
        try:
            # Try to initialize onboard temperature sensor (RP2040/ESP32)
            try:
                import esp32
                self._temp_sensor = 'esp32'
            except ImportError:
                pass

            # Initialize LED/light actuator pin
            try:
                self._light_pin = machine.Pin(2, machine.Pin.OUT)
                self._pwm_light = machine.PWM(self._light_pin)
                self._pwm_light.freq(1000)
                self._pwm_light.duty(0)
            except Exception:
                # Fallback: no hardware available (simulation mode)
                self._light_pin = None
                self._pwm_light = None
                print("[DeviceState] No light pin available, running in simulation mode")

        except Exception as e:
            print("[DeviceState] Hardware init error:", e)

    def read_temperature(self):
        """Read temperature from sensor."""
        try:
            if self._temp_sensor == 'esp32':
                import esp32
                raw = esp32.raw_temperature()
                # ESP32 returns Fahrenheit internally
                temp_c = (raw - 32) * 5.0 / 9.0
                return round(temp_c, 2)
            else:
                # Simulate temperature if no hardware sensor
                # Use ADC noise or time-based pseudo-random
                base_temp = 22.0
                variation = (time.ticks_ms() % 100) / 100.0 * 5.0 - 2.5
                return round(base_temp + variation, 2)
        except Exception as e:
            print("[DeviceState] Temp read error:", e)
            return 22.0

    def set_light(self, state=None, brightness=None):
        """Control the light actuator."""
        if state is not None:
            self.light_state = bool(state)

        if brightness is not None:
            self.light_brightness = max(0, min(100, int(brightness)))
            self.light_state = self.light_brightness > 0

        # Apply to hardware
        if self._pwm_light is not None:
            if self.light_state:
                duty = int(self.light_brightness * 1023 / 100)
                self._pwm_light.duty(duty)
            else:
                self._pwm_light.duty(0)
                self.light_brightness = 0
        elif self._light_pin is not None:
            self._light_pin.value(1 if self.light_state else 0)

    def get_light_status(self):
        """Return current light status as dict."""
        return {
            "on": self.light_state,
            "brightness": self.light_brightness
        }


class CoapResource:
    """Represents a single CoAP resource with handlers."""

    def __init__(self, path, get_handler=None, put_handler=None):
        self.path = path
        self.get_handler = get_handler
        self.put_handler = put_handler


class CoapServer:
    """Lightweight CoAP server for MicroPython IoT devices."""

    def __init__(self, host='0.0.0.0', port=COAP_PORT):
        self.host = host
        self.port = port
        self.resources = {}
        self.sock = None
        self.running = False
        self._msg_builder = CoapMessage()

    def add_resource(self, path, get_handler=None, put_handler=None):
        """Register a resource with its handlers."""
        self.resources[path] = CoapResource(path, get_handler, put_handler)
        print("[CoAP] Resource registered:", path)

    def _handle_request(self, data, addr):
        """Parse incoming request and dispatch to appropriate handler."""
        msg = CoapMessage.parse(data)
        if msg is None:
            return None

        uri_path = msg.get_uri_path()
        method = msg.get_method()

        print("[CoAP] {} {} from {}".format(
            {GET: 'GET', PUT: 'PUT', POST: 'POST', DELETE: 'DELETE'}.get(method, '?'),
            uri_path,
            addr
        ))

        # Determine response type
        if msg.msg_type == CON:
            resp_type = ACK
        else:
            resp_type = NON

        # Look up resource
        resource = self.resources.get(uri_path)

        if resource is None:
            # Resource not found
            response = self._msg_builder.build_response(
                resp_type, NOT_FOUND, msg.token, msg.message_id,
                payload="Not Found"
            )
            return response

        # Dispatch by method
        if method == GET:
            if resource.get_handler:
                try:
                    payload, content_format = resource.get_handler()
                    response = self._msg_builder.build_response(
                        resp_type, CONTENT, msg.token, msg.message_id,
                        payload=payload, content_format=content_format
                    )
                    return response
                except Exception as e:
                    print("[CoAP] GET handler error:", e)
                    response = self._msg_builder.build_response(
                        resp_type, BAD_REQUEST, msg.token, msg.message_id,
                        payload="Internal Error"
                    )
                    return response
            else:
                response = self._msg_builder.build_response(
                    resp_type, METHOD_NOT_ALLOWED, msg.token, msg.message_id,
                    payload="Method Not Allowed"
                )
                return response

        elif method == PUT:
            if resource.put_handler:
                try:
                    payload_data = msg.payload
                    result_payload, content_format = resource.put_handler(payload_data)
                    response = self._msg_builder.build_response(
                        resp_type, CHANGED, msg.token, msg.message_id,
                        payload=result_payload, content_format=content_format
                    )
                    return response
                except Exception as e:
                    print("[CoAP] PUT handler error:", e)
                    response = self._msg_builder.build_response(
                        resp_type, BAD_REQUEST, msg.token, msg.message_id,
                        payload="Bad Request"
                    )
                    return response
            else:
                response = self._msg_builder.build_response(
                    resp_type, METHOD_NOT_ALLOWED, msg.token, msg.message_id,
                    payload="Method Not Allowed"
                )
                return response

        else:
            response = self._msg_builder.build_response(
                resp_type, METHOD_NOT_ALLOWED, msg.token, msg.message_id,
                payload="Method Not Allowed"
            )
            return response

    def _create_socket(self):
        """Create and bind UDP socket."""
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind((self.host, self.port))
        # Set timeout so we can check self.running periodically
        self.sock.settimeout(1.0)
        print("[CoAP] Server listening on {}:{}".format(self.host, self.port))

    def start(self):
        """Start the CoAP server main loop."""
        self._create_socket()
        self.running = True

        print("[CoAP] Server started. Resources:")
        for path in self.resources:
            res = self.resources[path]
            methods = []
            if res.get_handler:
                methods.append("GET")
            if res.put_handler:
                methods.append("PUT")
            print("  {} [{}]".format(path, ", ".join(methods)))

        while self.running:
            try:
                data, addr = self.sock.recvfrom(256)  # Small buffer for IoT
                response = self._handle_request(data, addr)
                if response:
                    self.sock.sendto(response, addr)
            except OSError as e:
                # Timeout — just loop again
                if e.args[0] == 110 or e.args[0] == 11:  # ETIMEDOUT / EAGAIN
                    continue
                # Handle other errors
                if self.running:
                    print("[CoAP] Socket error:", e)
            except KeyboardInterrupt:
                print("\n[CoAP] Interrupted by user")
                self.running = False
            except Exception as e:
                print("[CoAP] Error:", e)

        self.stop()

    def stop(self):
        """Stop the server and release resources."""
        self.running = False
        if self.sock:
            self.sock.close()
            self.sock = None
        print("[CoAP] Server stopped")


