def handle_light_get():
    """GET /actuators/light — return current light state."""
    status = device.get_light_status()
    payload = json.dumps(status)
    return payload, APP_JSON


def handle_light_put(data):
    """PUT /actuators/light — set light state/brightness.
    
    Accepts JSON like:
      {"on": true}
      {"on": true, "brightness": 75}
      {"brightness": 50}
    Or plain text:
      "on" / "off"
      "0" - "100" (brightness)
    """
    try:
        # Try JSON first
        if data and data[0:1] == b'{':
            cmd = json.loads(data.decode('utf-8'))
            state = cmd.get('on', None)
            brightness = cmd.get('brightness', None)

            if state is not None and brightness is not None:
                device.set_light(state=state, brightness=brightness)
            elif state is not None:
                if state:
                    device.set_light(state=True, brightness=max(device.light_brightness, 100))
                else:
                    device.set_light(state=False, brightness=0)
            elif brightness is not None:
                device.set_light(brightness=brightness)
            else:
                return json.dumps({"error": "Provide 'on' and/or 'brightness'"}), APP_JSON
        else:
            # Plain text fallback
            text = data.decode('utf-8').strip().lower()
            if text == 'on':
                device.set_light(state=True, brightness=100)
            elif text == 'off':
                device.set_light(state=False, brightness=0)
            elif text.isdigit():
                device.set_light(brightness=int(text))
            else:
                return json.dumps({"error": "Invalid command"}), APP_JSON

        # Return updated status
        status = device.get_light_status()
        return json.dumps(status), APP_JSON

    except ValueError as e:
        return json.dumps({"error": "Invalid payload: " + str(e)}), APP_JSON


def handle_wellknown_core_get():
    """GET /.well-known/core — CoAP resource discovery."""
    links = []
    links.append('</sensors/temp>;rt="temperature";ct=50;if="sensor"')
    links.append('</actuators/light>;rt="light";ct=50;if="actuator"')
    payload = ','.join(links)
    return payload, 40  # application/link-format


