def main():
    """Initialize and start the CoAP server."""
    # Optional: Connect to WiFi first (for ESP32/ESP8266)
    try:
        import network
        sta = network.WLAN(network.STA_IF)
        if not sta.isconnected():
            print("[WiFi] Connecting...")
            sta.active(True)
            # Uncomment and set your WiFi credentials:
            # sta.connect('YOUR_SSID', 'YOUR_PASSWORD')
            # while not sta.isconnected():
            #     time.sleep(0.5)
        if sta.isconnected():
            print("[WiFi] Connected:", sta.ifconfig())
        else:
            print("[WiFi] Not connected, server will bind to 0.0.0.0")
    except ImportError:
        print("[Network] No WiFi module, assuming wired or local connection")

    # Create CoAP server
    server = CoapServer(host='0.0.0.0', port=COAP_PORT)

    # Register resources
    server.add_resource('/sensors/temp',
                        get_handler=handle_temp_get,
                        put_handler=handle_temp_put)

    server.add_resource('/actuators/light',
                        get_handler=handle_light_get,
                        put_handler=handle_light_put)

    # Resource discovery endpoint
    server.add_resource('/.well-known/core',
                        get_handler=handle_wellknown_core_get)

    # Start serving
    print("[Main] Starting CoAP server...")
    print("[Main] Test with: coap-client -m get coap://<device_ip>/sensors/temp")
    print("[Main] Test with: coap-client -m put -e '{\"on\":true,\"brightness\":75}' coap://<device_ip>/actuators/light")

    server.start()


if __name__ == '__main__':
    main()